-- Mon–Fri schedule for all demo dogs
INSERT INTO public.dog_schedule_days (dog_id, day_of_week)
SELECT d.id, dow.day
FROM public.dogs d
CROSS JOIN (VALUES (1), (2), (3), (4), (5)) AS dow(day)
WHERE d.company_id = 'a0000000-0000-0000-0000-000000000001'
ON CONFLICT (dog_id, day_of_week) DO NOTHING;
